DROP VIEW `user_discord_data`;--> statement-breakpoint
CREATE VIEW `user_discord_data` AS select "users"."id", "users"."name", "users"."email", "users"."email_verified", "users"."image", "users"."created_at", "users"."updated_at", "accounts"."id", "accounts"."account_id", "accounts"."provider_id", "accounts"."user_id", "accounts"."access_token", "accounts"."refresh_token", "accounts"."id_token", "accounts"."access_token_expires_at", "accounts"."refresh_token_expires_at", "accounts"."scope", "accounts"."password", "accounts"."created_at", "accounts"."updated_at" from "users" inner join "accounts" on "accounts"."user_id" = "users"."id" where "accounts"."provider_id" = 'discord';